33	// WriteFileAtomic writes data to name atomically by writing to a temporary file
34	// in the same directory and then renaming it into place. This prevents readers
35	// from observing a partially-written file if the process is interrupted.
36	// #nosec G304 -- callers intentionally operate on user-selected paths.
37	func WriteFileAtomic(name string, data []byte, perm os.FileMode) error {
38		dir := filepath.Dir(name)
39		tmp, err := os.CreateTemp(dir, ".tmp-safefs-*")
40		if err != nil {
41			return fmt.Errorf("safefs: create temp file: %w", err)
42		}
43		tmpName := tmp.Name()
44		// Best-effort cleanup on failure.
45		ok := false
46		defer func() {
47			if !ok {
48				_ = os.Remove(tmpName)
49			}
50		}()
51		if _, err := tmp.Write(data); err != nil {
52			_ = tmp.Close()
53			return fmt.Errorf("safefs: write temp file: %w", err)
54		}
55		if err := tmp.Chmod(perm); err != nil {
56			_ = tmp.Close()
57			return fmt.Errorf("safefs: chmod temp file: %w", err)
58		}
59		if err := tmp.Close(); err != nil {
60			return fmt.Errorf("safefs: close temp file: %w", err)
61		}
62		if err := os.Rename(tmpName, name); err != nil {
63			return fmt.Errorf("safefs: rename temp file: %w", err)
64		}
65		ok = true
66		return nil
67	}
